from itertools import permutations, combinations
import bisect

def _generate_balanced(max_len=8):
    balanced = set()
    digits = [d for d in range(1, 10) if d <= max_len]
    for r in range(1, len(digits) + 1):
        for combo in combinations(digits, r):
            total_len = sum(combo)
            if total_len > max_len:
                continue
            multiset = []
            for d in combo:
                multiset.extend([d] * d)
            for perm in set(permutations(multiset)):
                num = int(''.join(map(str, perm)))
                balanced.add(num)
    return sorted(balanced)

_BALANCED = _generate_balanced(8)

class Solution:
    def nextBeautifulNumber(self, n: int) -> int:
        idx = bisect.bisect_right(_BALANCED, n)
        return _BALANCED[idx]

