var nextBeautifulNumber = function(n) {
    function isBalanced(x) {
        const counts = {};
        const s = String(x);
        for (const ch of s) counts[ch] = (counts[ch] || 0) + 1;
        for (const d in counts) {
            if (Number(d) !== counts[d]) return false;
        }
        return true;
    }
    let x = n + 1;
    while (!isBalanced(x)) x++;
    return x;
};
